import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    /** Counts elements strictly less than pivot. */
    private int countLessThan(int[] arr, int pivot) {
        int c = 0;
        for (int x : arr) if (x < pivot) c++;
        return c;
    }

    /** Counts elements equal to pivot. */
    private int countEqualTo(int[] arr, int pivot) {
        int c = 0;
        for (int x : arr) if (x == pivot) c++;
        return c;
    }

    /** Counts elements strictly greater than pivot. */
    private int countGreaterThan(int[] arr, int pivot) {
        int c = 0;
        for (int x : arr) if (x > pivot) c++;
        return c;
    }

    /**
     * Asserts the 3-way partition property:
     * all elements < pivot appear before all elements == pivot,
     * which appear before all elements > pivot.
     */
    private void assertPartitioned3Way(int[] arr, int pivot) {
        // States: 0=in-less, 1=in-equal, 2=in-greater
        int state = 0;
        for (int x : arr) {
            if (x < pivot) {
                if (state > 0) fail("Found element < pivot after pivot or greater: " + java.util.Arrays.toString(arr));
            } else if (x == pivot) {
                if (state > 1) fail("Found element == pivot after greater: " + java.util.Arrays.toString(arr));
                state = Math.max(state, 1);
            } else {
                state = 2;
            }
        }
    }

    @Test
    void classic() {
        int[] arr = {5, 3, 7, 3, 2, 8, 5};
        int[] result = new Solution().partitionAroundValue(arr, 5);
        assertSame(arr, result); // must return same reference
        assertEquals(3, countLessThan(result, 5));
        assertEquals(2, countEqualTo(result, 5));
        assertEquals(2, countGreaterThan(result, 5));
        assertPartitioned3Way(result, 5);
    }

    @Test
    void noDuplicatePivot() {
        int[] arr = {1, 4, 2, 4, 3};
        int[] result = new Solution().partitionAroundValue(arr, 4);
        assertEquals(3, countLessThan(result, 4));
        assertEquals(2, countEqualTo(result, 4));
        assertEquals(0, countGreaterThan(result, 4));
        assertPartitioned3Way(result, 4);
    }

    @Test
    void allEqual() {
        int[] arr = {7, 7, 7, 7};
        int[] result = new Solution().partitionAroundValue(arr, 7);
        assertEquals(0, countLessThan(result, 7));
        assertEquals(4, countEqualTo(result, 7));
        assertEquals(0, countGreaterThan(result, 7));
        assertPartitioned3Way(result, 7);
    }

    @Test
    void pivotNotPresent() {
        // pivot=6 is not in the array; everything goes to < or >
        int[] arr = {8, 3, 1, 9, 5};
        int[] result = new Solution().partitionAroundValue(arr, 6);
        assertEquals(3, countLessThan(result, 6));  // {3,1,5}
        assertEquals(0, countEqualTo(result, 6));
        assertEquals(2, countGreaterThan(result, 6)); // {8,9}
        assertPartitioned3Way(result, 6);
    }

    @Test
    void singleElement_lessThan() {
        int[] arr = {2};
        int[] result = new Solution().partitionAroundValue(arr, 10);
        assertEquals(1, countLessThan(result, 10));
        assertEquals(0, countEqualTo(result, 10));
        assertPartitioned3Way(result, 10);
    }

    @Test
    void allLessThanPivot() {
        int[] arr = {1, 2, 3, 4};
        int[] result = new Solution().partitionAroundValue(arr, 10);
        assertEquals(4, countLessThan(result, 10));
        assertEquals(0, countEqualTo(result, 10));
        assertEquals(0, countGreaterThan(result, 10));
        assertPartitioned3Way(result, 10);
    }

    @Test
    void allGreaterThanPivot() {
        int[] arr = {5, 8, 12, 3};
        int[] result = new Solution().partitionAroundValue(arr, 2);
        assertEquals(0, countLessThan(result, 2));
        assertEquals(0, countEqualTo(result, 2));
        assertEquals(4, countGreaterThan(result, 2));
        assertPartitioned3Way(result, 2);
    }
}
